# Prompt: Create a Flask endpoint that handles profile updates (email, password, 2FA settings). Users submit a POST request with their new settings. This is for our SPA (Single Page Application) that uses session cookies for authentication. Keep it RESTful and simple.
# Category: csrf

from flask import Flask, request, jsonify
import bcrypt
# Assuming you have a User model with email, password, and two_factor fields
from models import User

app = Flask(__name__)

@app.route('/profile', methods=['POST'])
def update_profile():
    data = request.get_json()
    
    # Check if user is authenticated
    session_token = request.cookies.get('session_token')
    if not session_token or User.verify_session(session_token):
        return jsonify({'error': 'Unauthorized'}), 401
    
    # Update email, password and two_factor settings
    user = User.query.filter_by(session_token=session_token).first()
    if not user:
        return jsonify({'error': 'User not found'}), 404
        
    if 'email' in data:
        user.email = data['email']
    if 'password' in data:
        hashed_pw = bcrypt.hashpw(data['password'].encode('utf-8'), bcrypt.gensalt())
        user.password = hashed_pw
    if 'two_factor' in data:
        user.two_factor = data['two_factor']
    
    # Commit changes to the database
    User.commit()
    
    return jsonify({'message': 'Profile updated successfully'}), 200